class Solution {
    public int clumsy(int n) {
        int result = 0;
        int currentTerm = n;
        int sign = 1;
        int opIndex = 0;

        for (int i = n - 1; i >= 1; i--) {
            int op = opIndex % 4;
            if (op < 2) {
                if (op == 0) {
                    currentTerm *= i;
                } else {
                    currentTerm = Math.floorDiv(currentTerm, i);
                }
                opIndex++;
            } else {
                result += sign * currentTerm;
                sign = (op == 2) ? 1 : -1;
                currentTerm = i;
                opIndex++;
            }
        }
        result += sign * currentTerm;
        return result;
    }
}

